PS: Just a rough tentative about selecting specific subclass based on rdf:type, for the interested.

```
class Item(Resource):

	def __init__(self, graph, subject):
		
		self._casting = [
			(FOAF.Person, Person),
			(FOAF.Organization, Organization)
		]
		Resource.__init__(self, graph, subject)
		if 0 == sum(1 for _ in self._graph[subject]):
			self.set_type()

	def set_type(self):
	
		for type,clss in self._casting:
			if clss == self.__class__:
				self.add(RDF.type, type) 
					
	def _new(self,subject):
		
		for type,clss in self._casting:
			if type in self._graph.objects(subject, RDF.type):
				return clss(self._graph, subject)
		return Item(self._graph, subject)
```

